class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        vector<int> depth(1e5 + 1);
        for (int i = 0; i < nums.size(); ++i) {
            int d = 0;
            long long x = nums[i];
            while (x != 1) {
                int count = __builtin_popcountll(x);
                x = count;
                d++;
            }
            depth[i] = d;
        }

        vector<int> answer;
        for (auto& query : queries) {
            if (query[0] == 1) {
                int l = query[1], r = query[2], k = query[3];
                int count = 0;
                for (int i = l; i <= r; ++i) {
                    if (depth[i] == k) count++;
                }
                answer.push_back(count);
            } else {
                int idx = query[1];
                long long val = query[2];
                int d = 0;
                while (val != 1) {
                    int count = __builtin_popcountll(val);
                    val = count;
                    d++;
                }
                depth[idx] = d;
            }
        }
        return answer;
    }
};
